def validate_transformation(xform):
    # T1: Check all required fields are present
    required_fields = ['transformation_id', 'transformation_type', 'input_refs', 'output_refs', 'basis_refs', 'operation', 'retained_uncertainty', 'excluded_scope', 'revision_triggers']
    if not isinstance(xform, dict):
        return {"ok": False, "problems": ["xform must be a dict"]}

    missing = [f for f in required_fields if f not in xform]
    if missing:
        return {"ok": False, "problems": [f"Missing required fields: {missing}"]}

    # T2: transformation_type must be one of the allowed values
    allowed_types = ['RAW_REQUEST_TO_RESOLVED_INTENT', 'RESOLVED_INTENT_TO_RESEARCH_DESIGN', 'RESEARCH_AXIS_TO_RQ', 'OBSERVATION_TO_EVIDENCE', 'EVIDENCE_TO_CLAIM']
    if xform['transformation_type'] not in allowed_types:
        return {"ok": False, "problems": ["transformation_type must be one of the allowed values"]}

    # T3: input_refs, output_refs, basis_refs must each be a non-empty list
    list_fields = ['input_refs', 'output_refs', 'basis_refs']
    for field in list_fields:
        val = xform[field]
        if not isinstance(val, list):
            return {"ok": False, "problems": [f"{field} must be a list"]}
        if len(val) == 0:
            return {"ok": False, "problems": [f"{field} must be a non-empty list"]}

    # T4: retained_uncertainty, excluded_scope, revision_triggers must each be a list
    list_fields_optional = ['retained_uncertainty', 'excluded_scope', 'revision_triggers']
    for field in list_fields_optional:
        val = xform[field]
        if not isinstance(val, list):
            return {"ok": False, "problems": [f"{field} must be a list"]}

    # T5: operation must be a non-empty string
    if not isinstance(xform['operation'], str) or len(xform['operation']) == 0:
        return {"ok": False, "problems": ["operation must be a non-empty string"]}

    # T6: C-TOTALITY: non-dict or wrong-type field -> ok False, never crash, never ok True on malformed
    # Already handled above by type checks, but ensure no unexpected types slip through
    # Check transformation_id is a string (required field)
    if not isinstance(xform['transformation_id'], str):
        return {"ok": False, "problems": ["transformation_id must be a string"]}

    return {"ok": True, "problems": []}
